  1→import React, {useState, useCallback} from 'react';
  2→import {View, Text, TouchableOpacity, StyleSheet, Alert, ActivityIndicator} from 'react-native';
  3→import DocumentPicker from 'react-native-document-picker';
  4→import {getConfig, isConfigValid, ASR_PROVIDERS, LLM_PROVIDERS} from '../utils/config';
  5→import {transcribeAudio} from '../services/aliyunAsr';
  6→import {parseDocx, paragraphsToText} from '../services/docxParser';
  7→import {compareTexts} from '../services/zhipuCompare';
  8→import {generateDiffDocx} from '../services/docxGenerator';
  9→
 10→export default function HomeScreen({navigation}: any) {
 11→  const [audioFile, setAudioFile] = useState<any>(null);
 12→  const [docFile, setDocFile] = useState<any>(null);
 13→  const [loading, setLoading] = useState(false);
 14→  const [status, setStatus] = useState('');
 15→
 16→  const pickAudio = useCallback(async () => {
 17→    try {
 18→      const res = await DocumentPicker.pickSingle({type: DocumentPicker.types.audio});
 19→      setAudioFile(res);
 20→    } catch (e: any) {
 21→      if (!DocumentPicker.isCancel(e)) Alert.alert('错误', e.message);
 22→    }
 23→  }, []);
 24→
 25→  const pickDoc = useCallback(async () => {
 26→    try {
 27→      const res = await DocumentPicker.pickSingle({
 28→        type: [DocumentPicker.types.docx, DocumentPicker.types.doc],
 29→      });
 30→      setDocFile(res);
 31→    } catch (e: any) {
 32→      if (!DocumentPicker.isCancel(e)) Alert.alert('错误', e.message);
 33→    }
 34→  }, []);
 35→
 36→  const startCompare = useCallback(async () => {
 37→    if (!audioFile || !docFile) {
 38→      Alert.alert('提示', '请先选择录音和Word文档');
 39→      return;
 40→    }
 41→    const config = await getConfig();
 42→    if (!isConfigValid(config)) {
 43→      Alert.alert('提示', '请先在设置中配置API密钥', [
 44→        {text: '去设置', onPress: () => navigation.navigate('Settings')},
 45→      ]);
 46→      return;
 47→    }
 48→
 49→    setLoading(true);
 50→    try {
 51→      setStatus(`正在转写录音 (${ASR_PROVIDERS[config.asrProvider].name})...`);
 52→      const audioText = await transcribeAudio(audioFile.uri, config);
 53→
 54→      setStatus('正在解析文档...');
 55→      const paragraphs = await parseDocx(docFile.uri);
 56→      const docText = paragraphsToText(paragraphs);
 57→
 58→      setStatus(`正在对比内容 (${LLM_PROVIDERS[config.llmProvider].name})...`);
 59→      const result = await compareTexts(audioText, docText, config);
 60→
 61→      setStatus('正在生成对比文档...');
 62→      const outputPath = await generateDiffDocx(docFile.uri, result.diffs);
 63→
 64→      setLoading(false);
 65→      setStatus('');
 66→      navigation.navigate('Result', {
 67→        outputPath, summary: result.summary,
 68→        diffCount: result.diffs.length, audioText, docText,
 69→      });
 70→    } catch (e: any) {
 71→      setLoading(false);
 72→      setStatus('');
 73→      Alert.alert('处理失败', e.message);
 74→    }
 75→  }, [audioFile, docFile, navigation]);
 76→
 77→  return (
 78→    <View style={styles.container}>
 79→      <Text style={styles.title}>选择文件</Text>
 80→      <TouchableOpacity style={styles.fileBtn} onPress={pickAudio}>
 81→        <Text style={styles.fileBtnIcon}>🎤</Text>
 82→        <Text style={styles.fileBtnText}>{audioFile ? audioFile.name : '选择录音文件'}</Text>
 83→      </TouchableOpacity>
 84→      <TouchableOpacity style={styles.fileBtn} onPress={pickDoc}>
 85→        <Text style={styles.fileBtnIcon}>📄</Text>
 86→        <Text style={styles.fileBtnText}>{docFile ? docFile.name : '选择Word文档'}</Text>
 87→      </TouchableOpacity>
 88→      {loading ? (
 89→        <View style={styles.loadingBox}>
 90→          <ActivityIndicator size="large" color="#1a73e8" />
 91→          <Text style={styles.statusText}>{status}</Text>
 92→        </View>
 93→      ) : (
 94→        <TouchableOpacity
 95→          style={[styles.startBtn, (!audioFile || !docFile) && styles.startBtnDisabled]}
 96→          onPress={startCompare}>
 97→          <Text style={styles.startBtnText}>开始对比</Text>
 98→        </TouchableOpacity>
 99→      )}
100→      <TouchableOpacity style={styles.settingsLink} onPress={() => navigation.navigate('Settings')}>
101→        <Text style={styles.settingsText}>⚙️ API设置</Text>
102→      </TouchableOpacity>
103→    </View>
104→  );
105→}
106→
107→const styles = StyleSheet.create({
108→  container: {flex: 1, padding: 20, backgroundColor: '#f5f5f5'},
109→  title: {fontSize: 20, fontWeight: '600', marginBottom: 24, textAlign: 'center', color: '#333'},
110→  fileBtn: {
111→    flexDirection: 'row', alignItems: 'center', backgroundColor: '#fff',
112→    padding: 16, borderRadius: 12, marginBottom: 12,
113→    borderWidth: 1, borderColor: '#e0e0e0', borderStyle: 'dashed',
114→  },
115→  fileBtnIcon: {fontSize: 24, marginRight: 12},
116→  fileBtnText: {fontSize: 16, color: '#666', flex: 1},
