  3→export interface DiffItem {
  4→  docText: string;
  5→  audioText: string;
  6→  type: 'mismatch' | 'missing_in_audio' | 'extra_in_audio';
  7→  position: number;
  8→}
  9→
 10→export interface CompareResult {
 11→  diffs: DiffItem[];
 12→  summary: string;
 13→}
