import requests, json, re

PROMPT_TEMPLATE = '''你是一个专业的文档校对助手。请对比以下两段文字，找出所有不一致的地方。

【录音转写文字】
{audio_text}

【Word文档原文】
{doc_text}

请以JSON格式返回对比结果，格式如下：
{{
  "diffs": [
    {{
      "docText": "文档中的原文片段",
      "audioText": "录音中对应的文字（如果有）",
      "type": "mismatch 或 missing_in_audio 或 extra_in_audio",
      "position": 段落索引号（从0开始）
    }}
  ],
  "summary": "总结说明，共发现多少处不一致"
}}

注意：
- mismatch: 两边都有但内容不同
- missing_in_audio: 文档有但录音没提到
- extra_in_audio: 录音有但文档没有
- 语义相同但表述不同的不算差异（如"价格高"和"价格偏高"算一致）
- 口语化表达和书面表达的差异不算差异
- 只返回JSON，不要其他内容'''

def compare_texts(audio_text, doc_text, config):
    from config import LLM_PROVIDERS
    pid = config['llm_provider']
