import requests


class LLMClient:
    def __init__(self, base_url, api_key, model, provider_key="openai"):
        self.base_url = base_url.rstrip("/")
        self.api_key = api_key
        self.model = model
        self.provider_key = provider_key

    def test_connection(self):
        """发送最小请求测试连通性，返回 (success, message)"""
        try:
            if self.provider_key == "anthropic":
                url = f"{self.base_url}/messages"
                headers = {
                    "x-api-key": self.api_key,
                    "anthropic-version": "2023-06-01",
                    "Content-Type": "application/json",
                }
                body = {"model": self.model, "max_tokens": 10,
                        "messages": [{"role": "user", "content": "Hi"}]}
            else:
                url = f"{self.base_url}/chat/completions"
                headers = {
                    "Authorization": f"Bearer {self.api_key}",
                    "Content-Type": "application/json",
                }
                body = {"model": self.model, "max_tokens": 10,
                        "messages": [{"role": "user", "content": "Hi"}]}
            resp = requests.post(url, json=body, headers=headers, timeout=15)
            if resp.status_code == 200:
                return True, "连接成功"
            return False, f"HTTP {resp.status_code}: {resp.text[:200]}"
        except Exception as e:
            return False, str(e)

import os


class DocumentExtractor:
    def extract(self, file_path):
        ext = os.path.splitext(file_path)[1].lower()
        handlers = {
            '.pdf': self.extract_pdf,
            '.docx': self.extract_word,
            '.xlsx': self.extract_excel,
            '.png': self.extract_image, '.jpg': self.extract_image,
            '.jpeg': self.extract_image, '.bmp': self.extract_image,
        }
        handler = handlers.get(ext)
        if handler:
            return handler(file_path)
        return ""

    def _extract_table_kvs(self, cells):
        """从表格行的单元格中提取键值对，返回 'key：value' 格式列表"""
        kvs = []
        cleaned = [c.strip() if c else "" for c in cells]
        # 去重合并单元格
        deduped = list(dict.fromkeys(cleaned))
        deduped = [c for c in deduped if c]
        if len(deduped) >= 2 and len(deduped) % 2 == 0:
            for i in range(0, len(deduped), 2):
                kvs.append(f"{deduped[i]}：{deduped[i+1]}")
        return kvs

    def extract_pdf(self, path):
        import pdfplumber
        texts = []
        with pdfplumber.open(path) as pdf:
            for page in pdf.pages:
                t = page.extract_text()
                if t:
                    texts.append(t)
                for table in page.extract_tables():
                    for row in table:
                        kvs = self._extract_table_kvs(row)
                        if kvs:
                            texts.extend(kvs)
                        else:
                            texts.append(" ".join(cell or "" for cell in row))
        return "\n".join(texts)

    def extract_word(self, path):
        import docx
        doc = docx.Document(path)
        texts = [p.text for p in doc.paragraphs if p.text.strip()]
        for table in doc.tables:
            for row in table.rows:
                cells = [cell.text.strip() for cell in row.cells]
                kvs = self._extract_table_kvs(cells)
                if kvs:
                    texts.extend(kvs)
                else:
                    texts.append(" ".join(cells))
        return "\n".join(texts)

    def extract_excel(self, path):
        import openpyxl
        wb = openpyxl.load_workbook(path, read_only=True, data_only=True)
        texts = []
        for ws in wb.worksheets:
            for row in ws.iter_rows(values_only=True):
                vals = [str(c) for c in row if c is not None]
                if vals:
                    texts.append(" ".join(vals))
        wb.close()
        return "\n".join(texts)

    def extract_image(self, path):
        from app.core.ocr_client import LocalOCR
        ocr = LocalOCR()
        return ocr.recognize(path)

    def extract_clipboard(self):
        from PyQt5.QtWidgets import QApplication
        clip = QApplication.clipboard()
        return clip.text() or ""
